// And groups predicates with the AND operator between them.
func And(predicates ...predicate.IxLan) predicate.IxLan {
	return predicate.IxLan(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.IxLan) predicate.IxLan {
	return predicate.IxLan(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.IxLan) predicate.IxLan {
	return predicate.IxLan(sql.NotPredicates(p))
}
